import { useInView } from "./helpers";

const SPIKES = [
  { id: 1, label: "Festive hiring surges" },
  { id: 2, label: "Inventory scale-up" },
  { id: 3, label: "Accelerated onboarding cycles & compromised verification processes", wide: true },
];

/* Pie-chart-with-warning icon (SVG, matches Figma) */
function RiskIcon() {
  return (
    <svg width="48" height="48" viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg">
      {/* Pie slices */}
      <circle cx="24" cy="24" r="18" stroke="#333" strokeWidth="1.5" fill="none"/>
      {/* Filled quarter */}
      <path d="M24 24 L24 6 A18 18 0 0 1 42 24 Z" fill="#333"/>
      <path d="M24 24 L42 24 A18 18 0 0 1 24 42 Z" fill="#222"/>
      {/* Warning triangle */}
      <path d="M18 34 L24 23 L30 34 Z" fill="#e53e3e" stroke="#e53e3e" strokeWidth="0.5"/>
      <line x1="24" y1="27" x2="24" y2="30.5" stroke="white" strokeWidth="1.5" strokeLinecap="round"/>
      <circle cx="24" cy="32.5" r="0.8" fill="white"/>
    </svg>
  );
}

function SpikeCard({ item, delay, visible }) {
  return (
    <div style={{
      display: "flex", alignItems: "center", gap: 18,
      background: "#1a1a1a",
      borderRadius: 14,
      border: "1px solid #2a2a2a",
      padding: "18px 22px",
      opacity: visible ? 1 : 0,
      transform: visible ? "translateY(0)" : "translateY(24px)",
      transition: `opacity 0.55s ${delay}s, transform 0.55s ${delay}s`,
    }}>
      {/* Icon box */}
      <div style={{
        flexShrink: 0,
        width: 64, height: 64,
        background: "white",
        borderRadius: 10,
        display: "flex", alignItems: "center", justifyContent: "center",
      }}>
        <RiskIcon />
      </div>
      <span style={{
        fontFamily: "'Inter',sans-serif",
        fontSize: "clamp(15px,1.1vw,18px)",
        fontWeight: 500, color: "white", lineHeight: 1.5,
      }}>{item.label}</span>
    </div>
  );
}

export default function SpikesSection() {
  const [ref, visible] = useInView(0.2);

  return (
    <section style={{
      background: "radial-gradient(ellipse at 60% 40%, #1a0a0a 0%, #0d0d0d 60%, #0a0a12 100%)",
      padding: "80px 8vw 100px",
      display: "flex", flexDirection: "column", alignItems: "center",
      textAlign: "center",
    }}>

      {/* Vertical line + dot from top */}
      <div style={{
        display: "flex", flexDirection: "column", alignItems: "center",
        marginBottom: 36,
      }}>
        {/* Big dot at top */}
        <div style={{
          width: 22, height: 22, borderRadius: "50%",
          background: "#e53e3e",
          border: "3px solid #fff",
          boxShadow: "0 0 0 3px #e53e3e",
          flexShrink: 0,
        }}/>
        {/* Vertical line */}
        <div style={{
          width: 2, height: 80,
          background: "linear-gradient(180deg, #e53e3e 0%, #e53e3e88 100%)",
        }}/>
        {/* Small dot at bottom */}
        <div style={{
          width: 8, height: 8, borderRadius: "50%",
          background: "#e53e3e",
        }}/>
      </div>

      {/* Heading */}
      <h2 style={{
        fontFamily: "'Inter',sans-serif",
        fontSize: "clamp(22px,2.5vw,34px)",
        fontWeight: 700, color: "white",
        marginBottom: 48, lineHeight: 1.3,
      }}>
        These spikes typically occur due to
      </h2>

      {/* Cards grid */}
      <div ref={ref} style={{
        width: "100%", maxWidth: 1000,
        display: "grid",
        gridTemplateColumns: "1fr 1fr",
        gridTemplateRows: "auto auto",
        gap: 16,
        marginBottom: 52,
      }}>
        {/* First two — side by side */}
        {SPIKES.slice(0, 2).map((item, i) => (
          <SpikeCard key={item.id} item={item} delay={0.1 * i} visible={visible}/>
        ))}
        {/* Third — full width */}
        <div style={{ gridColumn: "1 / -1" }}>
          <SpikeCard item={SPIKES[2]} delay={0.2} visible={visible}/>
        </div>
      </div>

      {/* Body text */}
      <p style={{
        fontFamily: "'Inter',sans-serif",
        fontSize: "clamp(15px,1.1vw,19px)",
        color: "rgba(255,255,255,0.75)",
        lineHeight: 1.8, maxWidth: 820,
        opacity: visible ? 1 : 0,
        transform: visible ? "translateY(0)" : "translateY(16px)",
        transition: "opacity 0.55s 0.35s, transform 0.55s 0.35s",
      }}>
        When hiring volume spikes, verification compromises follow and{" "}
        <strong style={{ color: "#e53e3e" }}>risk rates</strong>{" "}
        inch upward. Even a <strong style={{ color: "white" }}>0.3%</strong>{" "}
        increase at scale translates into{" "}
        <strong style={{ color: "#e53e3e" }}>thousands</strong>{" "}
        of additional high-risk profiles entering the ecosystem.
      </p>
    </section>
  );
}
